import React, { useMemo } from "react";
import TagList from "../components/Main/TagList";
import Introduction from "../components/Main/Introduction";
import PostList from "../components/Main/PostList";
import { graphql } from "gatsby";
import queryString, { ParsedQuery } from "query-string";
import Template from "../components/Common/Template";

const TagPage = ({
  location: { search },
  data: {
    site: {
      siteMetadata: { title, description, siteUrl },
    },
    allMarkdownRemark: { edges },
    file: {
      childImageSharp: { gatsbyImageData },
      publicURL,
    },
  },
}) => {
  const parsed = queryString.parse(search);
  const selectedTag = typeof parsed.tag !== "string" || !parsed.tag ? "All" : parsed.tag;

  const tagList = useMemo(
    () =>
      edges.reduce(
        (
          list,
          {
            node: {
              frontmatter: { tags },
            },
          }
        ) => {
          tags.forEach((tag) => {
            if (list[tag] === undefined) list[tag] = 1;
            else list[tag]++;
          });

          list["All"]++;

          return list;
        },
        { All: 0 }
      ),
    []
  );

  return (
    <Template title={title} description={description} url={siteUrl} image={publicURL}>
      <TagList selectedTag={selectedTag} tagList={tagList} />
      <PostList selectedTag={selectedTag} posts={edges} />
    </Template>
  );
};

export default TagPage;

export const getPostList = graphql`
  query getPostList {
    site {
      siteMetadata {
        title
        description
        siteUrl
      }
    }
    allMarkdownRemark(sort: { order: DESC, fields: [frontmatter___date, frontmatter___title] }) {
      edges {
        node {
          id
          fields {
            slug
          }
          frontmatter {
            title
            summary
            date(formatString: "YYYY.MM.DD.")
            category
            tags
            thumbnail {
              childImageSharp {
                gatsbyImageData(width: 768, height: 400)
              }
            }
          }
        }
      }
    }
    file(name: { eq: "profile-image" }) {
      childImageSharp {
        gatsbyImageData(width: 120, height: 120)
      }
      publicURL
    }
  }
`;
