import React from "react";
import styled from "@emotion/styled";
import { Link } from "gatsby";

const TagListWrapper = styled.div`
  display: flex;
  flex-wrap: wrap;
  width: 768px;
  margin: 100px auto 20px;
  padding: 0 15px;
  color: #fff;
  background-color: #000;

  @media (max-width: 768px) {
    width: 100%;
    margin-top: 100px;
    padding: 0 20px;
  }
`;

const TagListItem = styled(({ active, ...props }) => <Link {...props} />)`
  margin-right: 20px;
  padding: 5px 0;
  font-size: 18px;
  font-weight: ${({ active }) => (active ? "800" : "400")};
  cursor: pointer;

  &:last-of-type {
    margin-right: 0;
  }

  @media (max-width: 768px) {
    font-size: 15px;
  }
`;

const TagList = ({ selectedTagList, tagList }) => {
  console.log(tagList);
  return (
    <TagListWrapper>
      {Object.entries(tagList)
        .sort(([, a], [, b]) => b - a)
        .map(([name, count]) => (
          <TagListItem to={`/tag/?tag=${name}`} active={name === selectedTagList} key={name}>
            #{name}({count})
          </TagListItem>
        ))}
    </TagListWrapper>
  );
};

export default TagList;
